SELECT COUNT(*)
FROM report
WHERE reporter_id = #{reporterId}
  AND target_type = #{targetType}
  AND target_id = #{targetId}
  AND status != 'rejected'

SELECT r.*
FROM report r
WHERE r.reporter_id = #{reporterId}
ORDER BY r.created_at DESC
LIMIT #{pageSize} OFFSET #{offset}

SELECT r.id, r.reporter_id AS reporterId, ur.nickname AS reporterName, ur.avatar, r.target_type AS targetType, r.target_id AS targetId, r.target_user_id AS targetUserId, tu.nickname AS targetUserName, r.reason_type AS reasonType, r.reason_detail AS reasonDetail, r.evidence_urls AS evidenceUrls, r.status, r.admin_id AS adminId, au.nickname AS adminName, r.admin_remark AS adminRemark, r.processed_at AS processedAt, r.created_at AS createdAt, r.updated_at AS updatedAt, CASE r.target_type WHEN 'article' THEN a.title WHEN 'comment' THEN CONCAT('评论: ', LEFT(c.content, 50)) WHEN 'user' THEN CONCAT('用户: ', tu.nickname) ELSE '未知' END AS targetTitle, AS priority FROM report r LEFT JOIN user ur ON r.reporter_id = ur.id LEFT JOIN user tu ON r.target_user_id = tu.id LEFT JOIN user au ON r.admin_id = au.id LEFT JOIN article a ON r.target_type = 'article' AND r.target_id = a.id LEFT JOIN comment c ON r.target_type = 'comment' AND r.target_id = c.id
r.status = #{req.status}
r.status = 'pending'
AND r.target_type = #{req.targetType}
AND r.reason_type = #{req.reasonType}
AND r.reason_type IN ('harassment', 'copyright')
AND r.reason_type = 'inappropriate'
AND r.reason_type IN ('spam', 'other')
AND ( ur.nickname LIKE CONCAT('%', #{req.keyword}, '%') OR a.title LIKE CONCAT('%', #{req.keyword}, '%') OR c.content LIKE CONCAT('%', #{req.keyword}, '%') OR r.reason_detail LIKE CONCAT('%', #{req.keyword}, '%') )
ORDER BY , r.created_at DESC LIMIT #{req.pageSize} OFFSET #{offset}

SELECT COUNT(DISTINCT r.id) FROM report r LEFT JOIN user tu ON r.target_user_id = tu.id LEFT JOIN article a ON r.target_type = 'article' AND r.target_id = a.id LEFT JOIN comment c ON r.target_type = 'comment' AND r.target_id = c.id
r.status = #{req.status}
